mapper.select:
/* StatsMgmtMapper.getUsimChgHstExcel */ SELECT USIM_CHG_DATE , CONTRACT_NUM , SVC_CNTR_NO , USIM_MODNM , USIM_NO , SUB_STATUS_NM , LST_COM_ACTV_DATE , CHG_TYPE , MAX(HDN_YN) AS HDN_YN FROM ( SELECT TO_CHAR(TO_DATE(USIM.CHG_DTTM, 'YYYYMMDDHH24MISS'), 'YYYY-MM-DD HH24:MI:SS') AS USIM_CHG_DATE , USIM.CONTRACT_NUM AS CONTRACT_NUM , SUB.SVC_CNTR_NO AS SVC_CNTR_NO , USIM.USIM_MODNM AS USIM_MODNM , USIM.USIM_NO AS USIM_NO , FN_GET_CODENM('MSP0003', SUB.SUB_STATUS) AS SUB_STATUS_NM , TO_CHAR(TO_DATE(SUB.LST_COM_ACTV_DATE, 'YYYYMMDD'), 'YYYY-MM-DD') AS LST_COM_ACTV_DATE , FN_GET_CODENM('MSP0005',HST.EVNT_CD) AS CHG_TYPE , DECODE(CHG.CONTRACT_NUM, NULL, '', 'Y') AS HDN_YN FROM MSP_USIM_CHG_HST USIM , MSP_JUO_SUB_INFO SUB , MSP_JUO_SUB_INFO_HIST HST , (SELECT CONTRACT_NUM, EVNT_TRTM_NO FROM MSP_DVC_CHG_AGNT_HST WHERE REQUEST_KEY IS NOT NULL) CHG WHERE USIM.CONTRACT_NUM = SUB.CONTRACT_NUM AND CHG_DTTM > '20251104235959' /* 25년 11월 4일까지 이력을 기준 데이터로 사용 */ AND USIM.CONTRACT_NUM = HST.CONTRACT_NUM AND USIM.CHG_DTTM = HST.EVNT_CHANGE_DATE AND USIM.USIM_NO = HST.ICC_ID AND HST.CONTRACT_NUM = CHG.CONTRACT_NUM(+) AND HST.EVNT_TRTM_NO = CHG.EVNT_TRTM_NO(+)
AND USIM.CHG_DTTM BETWEEN #{srchStrtDt} || '000000' AND #{srchEndDt} || '235959'
AND USIM.CONTRACT_NUM = #{searchName}
AND SUB.SVC_CNTR_NO = #{searchName}
) GROUP BY USIM_CHG_DATE,CONTRACT_NUM,SVC_CNTR_NO,USIM_MODNM,USIM_NO,SUB_STATUS_NM,LST_COM_ACTV_DATE,CHG_TYPE ORDER BY USIM_CHG_DATE DESC
